module top_module(
input Reset,
input Clock,
input In, 
output [3:0] Out
);reg [3:0] unused_Counter;
reg toggle;






always @(posedge Clock, negedge Reset) begin
	if ( Reset == 0 ) 
		unused_Counter <= 4'b0000;
	else begin
		if ((In==1) & (toggle==0)) begin
			unused_Counter <= unused_Counter + 1'b1;
			toggle <= 1;
	    end
		else if (In==0) begin
			toggle <= 0;
		end
	end
end

assign Out = unused_Counter;

endmodule
